headStyles:
:root {
  --tier-stonewall: #ff5a36;
  --tier-founding: #ffb300;
  --tier-builder: #2bb673;
  --tier-circle: #2c8df0;
  --tier-patron: #a14fff;
}

body { background: var(--dark-bg, #0b1f33); }

/* HERO STATS */
.hero-stats {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 1rem;
  max-width: 880px;
  margin: 1.5rem auto 0;
}
.hero-stat {
  background: rgba(19, 45, 68, 0.55);
  border: 1px solid var(--dark-bg-light, #1a3a52);
  border-radius: 12px;
  padding: 1rem 1.25rem;
  text-align: center;
  position: relative;
  overflow: hidden;
}
.hero-stat::before {
  content: "";
  position: absolute;
  top: 0; left: 0; right: 0; height: 3px;
  background: var(--pride-gradient, linear-gradient(90deg,#ff5a36,#ffb300,#2bb673,#2c8df0,#a14fff));
}
.hero-stat .num {
  font-family: "Montserrat", sans-serif;
  font-weight: 700;
  font-size: clamp(1.5rem, 4vw, 2rem);
  color: var(--text-white, #fff);
  line-height: 1.1;
}
.hero-stat .label {
  font-family: "Roboto Slab", serif;
  color: var(--text-light, #c5d2dd);
  font-size: 0.78rem;
  margin-top: 0.25rem;
  letter-spacing: 0.04em;
  text-transform: uppercase;
}
.hero-stat .sub {
  font-family: "Roboto Slab", serif;
  color: var(--text-light, #c5d2dd);
  font-size: 0.85rem;
  margin-top: 0.4rem;
}

/* PROGRESS BAR */
.goal-block { max-width: 720px; margin: 2.25rem auto 0; }

/* TIER CHIPS */
.tier-chips-section { padding: 2rem 0 1rem; }
.tier-chips-section h2 {
  font-family: "Montserrat", sans-serif;
  font-size: 1.35rem;
  color: var(--text-white, #fff);
  text-align: center;
  margin-bottom: 0.4rem;
}
.tier-chips-section .lede {
  font-family: "Roboto Slab", serif;
  color: var(--text-light, #c5d2dd);
  text-align: center;
  max-width: 640px;
  margin: 0 auto 1.5rem;
  line-height: 1.6;
  font-size: 0.95rem;
}
.tier-chips {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
  gap: 0.75rem;
  max-width: 1080px;
  margin: 0 auto;
}
.tier-chip {
  background: rgba(19, 45, 68, 0.55);
  border: 1px solid var(--dark-bg-light, #1a3a52);
  border-radius: 12px;
  padding: 1rem 1rem;
  text-align: center;
  cursor: pointer;
  transition: transform 0.15s ease, border-color 0.2s ease, background-color 0.2s ease;
  position: relative;
}
.tier-chip:hover { transform: translateY(-2px); border-color: rgba(255,255,255,0.35); }
.tier-chip[aria-pressed="true"] {
  border-color: var(--text-white, #fff);
  background: rgba(255,255,255,0.06);
}
.tier-chip .dot {
  display: inline-block;
  width: 10px; height: 10px;
  border-radius: 50%;
  margin-right: 0.4rem;
  vertical-align: middle;
}
.tier-chip .name {
  font-family: "Montserrat", sans-serif;
  font-weight: 700;
  font-size: 0.95rem;
  color: var(--text-white, #fff);
}
.tier-chip .price {
  font-family: "Roboto Slab", serif;
  color: var(--text-light, #c5d2dd);
  font-size: 0.8rem;
  margin-top: 0.3rem;
}
.tier-chip .count {
  font-family: "Montserrat", sans-serif;
  font-size: 0.72rem;
  color: var(--text-light, #c5d2dd);
  margin-top: 0.4rem;
  opacity: 0.8;
}

.cta-row { text-align: center; margin: 2rem 0 1.5rem; }

/* ENDORSED BY STRIP */
.endorsed-strip {
  max-width: 1080px;
  margin: 1rem auto 0;
  background: linear-gradient(180deg, rgba(255,255,255,0.04), rgba(255,255,255,0.01));
  border: 1px solid var(--dark-bg-light, #1a3a52);
  border-radius: 12px;
  padding: 1rem 1.25rem;
}
.endorsed-strip .label {
  font-family: "Montserrat", sans-serif;
  font-weight: 700;
  font-size: 0.78rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--text-light, #c5d2dd);
  margin-bottom: 0.5rem;
}
.endorsed-strip .roster {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem 1rem;
}
.endorsed-strip a {
  font-family: "Roboto Slab", serif;
  color: var(--text-white, #fff);
  text-decoration: none;
  font-size: 0.95rem;
  border-bottom: 1px dotted rgba(255,255,255,0.3);
  padding-bottom: 1px;
}
.endorsed-strip a:hover { border-bottom-color: var(--text-white, #fff); }

/* DIRECTORY CONTROLS */
.directory-controls {
  display: grid;
  grid-template-columns: minmax(0, 1.6fr) minmax(0, 1fr) minmax(0, 1fr) minmax(0, 1.1fr);
  gap: 0.75rem;
  max-width: 1080px;
  margin: 0 auto 1rem;
  align-items: stretch;
}
.directory-controls input,
.directory-controls select {
  width: 100%;
  min-height: 44px;
  background: rgba(19, 45, 68, 0.7);
  border: 1px solid var(--dark-bg-light, #1a3a52);
  color: var(--text-white, #fff);
  font-family: "Roboto Slab", serif;
  font-size: 0.95rem;
  padding: 0.7rem 0.9rem;
  border-radius: 10px;
  outline: none;
  appearance: none;
  -webkit-appearance: none;
}
.directory-controls select {
  background-image: url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' width='12' height='8' viewBox='0 0 12 8'><path d='M1 1l5 5 5-5' stroke='%23c5d2dd' stroke-width='1.6' fill='none' stroke-linecap='round'/></svg>");
  background-repeat: no-repeat;
  background-position: right 0.85rem center;
  padding-right: 2.2rem;
}
.directory-controls input:focus,
.directory-controls select:focus {
  border-color: var(--color-blue, #2c8df0);
  box-shadow: 0 0 0 3px rgba(44,141,240,0.22);
}
.directory-controls input::placeholder { color: rgba(255,255,255,0.5); }

/* Elected-only toggle styled as a proper pressable pill that matches
   the height of the inputs/selects and visually flips when checked. */
.toggle-elected {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.55rem;
  width: 100%;
  min-height: 44px;
  background: rgba(19, 45, 68, 0.7);
  border: 1px solid var(--dark-bg-light, #1a3a52);
  border-radius: 10px;
  padding: 0.55rem 0.9rem;
  cursor: pointer;
  user-select: none;
  font-family: "Roboto Slab", serif;
  color: var(--text-white, #fff);
  font-size: 0.9rem;
  line-height: 1.2;
  white-space: nowrap;
  transition: border-color 0.15s ease, background-color 0.15s ease, color 0.15s ease;
}
.toggle-elected:hover { border-color: rgba(255,255,255,0.35); }
.toggle-elected:focus-within {
  border-color: var(--color-blue, #2c8df0);
  box-shadow: 0 0 0 3px rgba(44,141,240,0.25);
}
.toggle-elected:has(input:checked) {
  border-color: #7fb6ff;
  background: rgba(44, 141, 240, 0.18);
  color: #eaf3ff;
}
.toggle-elected input {
  flex: none;
  width: 18px;
  height: 18px;
  margin: 0;
  accent-color: var(--color-blue, #2c8df0);
  cursor: pointer;
}

.result-meta {
  max-width: 1080px;
  margin: 0.25rem auto 1rem;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
  font-family: "Roboto Slab", serif;
  color: var(--text-light, #c5d2dd);
  font-size: 0.9rem;
}
.result-meta .clear {
  background: none;
  border: none;
  color: var(--color-blue, #2c8df0);
  cursor: pointer;
  font-family: "Roboto Slab", serif;
  font-size: 0.9rem;
  padding: 0;
}
.result-meta .clear:hover { text-decoration: underline; }

/* MEMBER GRID */
.member-grid {
  max-width: 1080px;
  margin: 0 auto;
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
  gap: 1rem;
}
.member-card {
  position: relative;
  background: rgba(19, 45, 68, 0.55);
  border: 1px solid var(--dark-bg-light, #1a3a52);
  border-radius: 14px;
  padding: 1.1rem 1.1rem 1rem;
  overflow: hidden;
  content-visibility: auto;
  contain-intrinsic-size: auto 200px;
  transition: transform 0.15s ease, border-color 0.2s ease;
  display: flex;
  flex-direction: column;
  min-height: 9rem;
}
.member-card .joined { margin-top: auto; }
.member-card:hover { transform: translateY(-2px); border-color: rgba(255,255,255,0.25); }
.member-card::before {
  content: "";
  position: absolute;
  top: 0; left: 0; bottom: 0;
  width: 4px;
  background: var(--tier-color, var(--pride-gradient, linear-gradient(180deg,#ff5a36,#ffb300,#2bb673,#2c8df0,#a14fff)));
}
.member-card .pos {
  position: absolute;
  top: 0.7rem;
  right: 0.85rem;
  font-family: "Montserrat", sans-serif;
  font-size: 0.72rem;
  color: var(--text-light, #c5d2dd);
  letter-spacing: 0.05em;
}
.member-card .name-row {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  flex-wrap: wrap;
}
.member-card .name {
  font-family: "Montserrat", sans-serif;
  font-size: 1.05rem;
  font-weight: 700;
  color: var(--text-white, #fff);
  line-height: 1.2;
}
.member-card .elected-pin {
  display: inline-flex;
  align-items: center;
  gap: 0.25rem;
  font-family: "Montserrat", sans-serif;
  font-size: 0.62rem;
  font-weight: 700;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  background: rgba(44, 141, 240, 0.15);
  color: #7fb6ff;
  border: 1px solid rgba(127, 182, 255, 0.4);
  padding: 0.18rem 0.45rem;
  border-radius: 999px;
}
.member-card .office {
  font-family: "Roboto Slab", serif;
  color: #c8dcf2;
  font-size: 0.82rem;
  margin-top: 0.25rem;
  line-height: 1.3;
}
.member-card .meta {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  margin-top: 0.7rem;
  flex-wrap: wrap;
}
.member-card .tier-tag {
  display: inline-flex;
  align-items: center;
  gap: 0.35rem;
  font-family: "Montserrat", sans-serif;
  font-size: 0.7rem;
  font-weight: 700;
  letter-spacing: 0.04em;
  color: var(--text-white, #fff);
  background: rgba(255,255,255,0.04);
  border: 1px solid rgba(255,255,255,0.1);
  border-radius: 999px;
  padding: 0.18rem 0.55rem;
}
.member-card .tier-tag .dot { width: 8px; height: 8px; border-radius: 50%; }
.member-card .loc {
  font-family: "Roboto Slab", serif;
  font-size: 0.85rem;
  color: var(--text-light, #c5d2dd);
}
.member-card .quote {
  margin-top: 0.7rem;
  font-family: "Roboto Slab", serif;
  font-size: 0.85rem;
  color: var(--text-light, #c5d2dd);
  font-style: italic;
  line-height: 1.4;
  border-left: 2px solid rgba(255,255,255,0.15);
  padding-left: 0.6rem;
}
.member-card .joined {
  margin-top: 0.7rem;
  font-family: "Montserrat", sans-serif;
  font-size: 0.7rem;
  color: var(--text-light, #c5d2dd);
  opacity: 0.8;
  letter-spacing: 0.04em;
  text-transform: uppercase;
}

/* PLACEHOLDER CARDS */
.member-card.placeholder {
  background: repeating-linear-gradient(
    135deg,
    rgba(255,255,255,0.02),
    rgba(255,255,255,0.02) 10px,
    rgba(255,255,255,0.04) 10px,
    rgba(255,255,255,0.04) 20px
  );
  border-style: dashed;
  opacity: 0.55;
}
.member-card.placeholder::before { background: rgba(255,255,255,0.15); }
.member-card.placeholder .name { color: var(--text-light, #c5d2dd); }

.load-more-row { max-width: 1080px; margin: 1.5rem auto 0; text-align: center; }
.load-more-row button {
  background: rgba(255,255,255,0.05);
  border: 1px solid var(--dark-bg-light, #1a3a52);
  color: var(--text-white, #fff);
  font-family: "Montserrat", sans-serif;
  font-weight: 700;
  font-size: 0.85rem;
  letter-spacing: 0.05em;
  padding: 0.7rem 1.4rem;
  border-radius: 10px;
  cursor: pointer;
}
.load-more-row button:hover { background: rgba(255,255,255,0.1); }

.no-results {
  max-width: 600px;
  margin: 2rem auto;
  text-align: center;
  padding: 2rem 1.5rem;
  border: 1px dashed rgba(255,255,255,0.15);
  border-radius: 12px;
  background: rgba(19, 45, 68, 0.3);
}
.no-results h4 {
  font-family: "Montserrat", sans-serif;
  font-size: 1.05rem;
  color: var(--text-white, #fff);
  margin-bottom: 0.4rem;
}
.no-results p {
  font-family: "Roboto Slab", serif;
  color: var(--text-light, #c5d2dd);
  font-size: 0.9rem;
}

/* Result-meta: never let the count + clear button collide on narrow widths. */
@media (max-width: 480px) {
  .result-meta {
    flex-direction: column;
    align-items: flex-start;
    gap: 0.35rem;
  }
}

/* Tablet: drop the directory controls to two columns, search spans full
   width so it stays readable. */
@media (max-width: 900px) {
  .directory-controls {
    grid-template-columns: minmax(0, 1fr) minmax(0, 1fr);
  }
  .directory-controls .field:first-child { grid-column: 1 / -1; }
}

/* Small tablet / large phone: 2-up hero stats reads better than 1-up. */
@media (max-width: 720px) {
  .hero-stats { grid-template-columns: repeat(2, minmax(0, 1fr)); gap: 0.6rem; }
  .hero-stat { padding: 0.85rem 0.9rem; }
  .endorsed-strip .roster { gap: 0.45rem 0.9rem; }
  .tier-chips-section h2 { font-size: 1.2rem; }
  .cta-row .btn { width: 100%; max-width: 360px; }
}

/* Phone: full-width controls, the toggle becomes its own row. */
@media (max-width: 600px) {
  .directory-controls {
    grid-template-columns: 1fr;
  }
  .directory-controls .field:first-child { grid-column: auto; }
}

/* Very narrow phone: collapse hero stats so numbers don't wrap. */
@media (max-width: 420px) {
  .hero-stats { grid-template-columns: 1fr; }
  .member-grid { grid-template-columns: 1fr; }
}

