var FOUNDING_GOAL = 1969;
var PAGE_SIZE = 60;

var state = {
  search: "",
  county: "",
  tiers: new Set(),
  electedOnly: false,
  sort: "newest",
  visibleCount: PAGE_SIZE
};

var tierMap = TIERS.reduce(function (acc, t) { acc[t.id] = t; return acc; }, {});
function tierColor(id) { return (tierMap[id] && tierMap[id].color) || "rgba(255,255,255,0.4)"; }
function tierName(id)  { return (tierMap[id] && tierMap[id].name)  || id; }

function escapeHtml(s) {
  if (s == null) return "";
  return String(s)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

function formatJoined(iso) {
  if (!iso) return "";
  var d = new Date(iso + "T12:00:00");
  if (isNaN(d.getTime())) return "";
  return d.toLocaleDateString("en-US", { month: "long", year: "numeric" });
}

function relativeTime(iso) {
  if (!iso) return "";
  var d = new Date(iso + "T12:00:00");
  if (isNaN(d.getTime())) return "";
  var diffMs = Date.now() - d.getTime();
  var days = Math.floor(diffMs / 86400000);
  if (days < 1) return "Joined today";
  if (days === 1) return "Joined yesterday";
  if (days < 7) return "Joined " + days + " days ago";
  if (days < 30) {
    var w = Math.floor(days / 7);
    return "Joined " + w + " week" + (w === 1 ? "" : "s") + " ago";
  }
  return "Joined " + d.toLocaleDateString("en-US", { month: "short", year: "numeric" });
}

function renderTierChips() {
  var host = document.getElementById("tierChips");
  var counts = {};
  TIERS.forEach(function (t) { counts[t.id] = 0; });
  MEMBERS.forEach(function (m) {
    if (m.publicConsent && counts.hasOwnProperty(m.tier)) counts[m.tier]++;
  });

  host.innerHTML = TIERS.map(function (t) {
    var pressed = state.tiers.has(t.id);
    return ''
      + '<button type="button" class="tier-chip" data-tier="' + t.id + '" aria-pressed="' + pressed + '">'
      +   '<div class="name"><span class="dot" style="background:' + t.color + '"></span>' + escapeHtml(t.name) + '</div>'
      +   '<div class="price">' + escapeHtml(t.price) + '</div>'
      +   '<div class="count">' + counts[t.id] + ' member' + (counts[t.id] === 1 ? '' : 's') + '</div>'
      + '</button>';
  }).join("");

  host.querySelectorAll(".tier-chip").forEach(function (btn) {
    btn.addEventListener("click", function () {
      var t = btn.getAttribute("data-tier");
      if (state.tiers.has(t)) state.tiers.delete(t); else state.tiers.add(t);
      btn.setAttribute("aria-pressed", state.tiers.has(t));
      state.visibleCount = PAGE_SIZE;
      renderGrid();
    });
  });
}

function renderCountyOptions() {
  var sel = document.getElementById("countyFilter");
  var present = {};
  MEMBERS.forEach(function (m) { if (m.publicConsent && m.county) present[m.county] = true; });
  var html = '<option value="">All Ohio counties</option>';
  OHIO_COUNTIES.slice().sort().forEach(function (c) {
    var has = present[c];
    html += '<option value="' + escapeHtml(c) + '">' + escapeHtml(c)
          + (has ? '' : ' (no members yet)') + '</option>';
  });
  sel.innerHTML = html;
}

function renderEndorsedStrip() {
  var electeds = MEMBERS.filter(function (m) { return m.publicConsent && m.electedOffice; });
  var strip = document.getElementById("endorsedStrip");
  var roster = document.getElementById("endorsedRoster");
  if (electeds.length === 0) { strip.hidden = true; return; }
  strip.hidden = false;
  roster.innerHTML = electeds.map(function (m) {
    var label = escapeHtml(m.displayName)
      + ' <span style="color:var(--text-light,#c5d2dd); font-size:0.85em;">('
      + escapeHtml(m.electedOffice)
      + (m.jurisdiction ? ', ' + escapeHtml(m.jurisdiction) : '')
      + ')</span>';
    return '<a href="#member-' + m.id + '">' + label + '</a>';
  }).join("");
}

function renderHeroStats() {
  var visible = MEMBERS.filter(function (m) { return m.publicConsent; });
  var count = visible.length;

  var counties = {};
  visible.forEach(function (m) { if (m.county) counties[m.county] = true; });
  var countyCount = Object.keys(counties).length;

  var newest = visible.slice().sort(function (a, b) {
    var d = (b.joinedAt || "").localeCompare(a.joinedAt || "");
    return d !== 0 ? d : (b.id || 0) - (a.id || 0);
  })[0];

  document.getElementById("statMembers").textContent = count.toLocaleString();
  document.getElementById("statCounties").textContent = countyCount;
  if (newest) {
    var firstName = newest.displayName.split(" ")[0];
    var label = firstName + (newest.county ? " from " + newest.county + " County" : "");
    document.getElementById("statNewestName").textContent = label;
    document.getElementById("statNewestWhen").textContent = relativeTime(newest.joinedAt);
  }

  var pct = Math.min(100, (count / FOUNDING_GOAL) * 100);
  var bar = document.getElementById("goalFill");
  var text = document.getElementById("progressText");
  if (bar) bar.style.width = pct + "%";
  if (text) text.textContent = count.toLocaleString() + " of 1,969 Founding Members";
}

function getFiltered() {
  var q = state.search.trim().toLowerCase();
  var rows = MEMBERS.filter(function (m) {
    if (!m.publicConsent) return false;
    if (state.electedOnly && !m.electedOffice) return false;
    if (state.county && m.county !== state.county) return false;
    if (state.tiers.size > 0 && !state.tiers.has(m.tier)) return false;
    if (q) {
      var hay = [m.displayName, m.city, m.county, m.electedOffice, m.jurisdiction]
        .filter(Boolean).join(" ").toLowerCase();
      if (hay.indexOf(q) === -1) return false;
    }
    return true;
  });

  switch (state.sort) {
    case "oldest":
      rows.sort(function (a, b) { return (a.joinedAt || "").localeCompare(b.joinedAt || ""); });
      break;
    case "az":
      rows.sort(function (a, b) { return (a.sortName || a.displayName).localeCompare(b.sortName || b.displayName); });
      break;
    case "county":
      rows.sort(function (a, b) { return (a.county || "zzz").localeCompare(b.county || "zzz"); });
      break;
    case "position":
      rows.sort(function (a, b) { return a.id - b.id; });
      break;
    case "newest":
    default:
      rows.sort(function (a, b) {
        var d = (b.joinedAt || "").localeCompare(a.joinedAt || "");
        return d !== 0 ? d : b.id - a.id;
      });
  }
  return rows;
}

function memberCardHTML(m) {
  var color = tierColor(m.tier);
  var hasElected = !!m.electedOffice;
  var quote = m.quote ? '<div class="quote">&ldquo;' + escapeHtml(m.quote) + '&rdquo;</div>' : '';
  // For elected members, the role line replaces the location line so every
  // card has exactly one location/role row and they align in the grid.
  var loc;
  if (hasElected) {
    loc = '<div class="loc">'
      + escapeHtml(m.electedOffice + (m.jurisdiction ? ', ' + m.jurisdiction : ''))
      + '</div>';
  } else if (m.city || m.county) {
    loc = '<div class="loc">'
      + escapeHtml([m.city, m.county ? m.county + " County" : null].filter(Boolean).join(", "))
      + '</div>';
  } else {
    loc = '<div class="loc" style="opacity:0.55;">Ohio</div>';
  }
  var pin = hasElected
    ? '<span class="elected-pin" title="Elected official">'
      + '<svg width="9" height="9" viewBox="0 0 24 24" fill="currentColor" aria-hidden="true">'
      + '<path d="M12 2l2.39 4.84L20 7.27l-3.91 3.81.92 5.39L12 13.93l-5.01 2.54.92-5.39L4 7.27l5.61-.43L12 2z"/>'
      + '</svg>Elected</span>'
    : '';
  var joined = formatJoined(m.joinedAt)
    ? "Founding Member since " + formatJoined(m.joinedAt)
    : "Founding Member";
  return ''
    + '<article class="member-card" id="member-' + m.id + '" style="--tier-color:' + color + ';">'
    +   '<div class="pos">#' + m.id + '</div>'
    +   '<div class="name-row">'
    +     '<div class="name">' + escapeHtml(m.displayName) + '</div>'
    +     pin
    +   '</div>'
    +   '<div class="meta">'
    +     '<span class="tier-tag"><span class="dot" style="background:' + color + ';"></span>' + escapeHtml(tierName(m.tier)) + '</span>'
    +     loc
    +   '</div>'
    +   quote
    +   '<div class="joined">' + escapeHtml(joined) + '</div>'
    + '</article>';
}

function placeholderCardHTML(num) {
  return ''
    + '<article class="member-card placeholder" aria-hidden="true">'
    +   '<div class="pos">#' + num + '</div>'
    +   '<div class="name-row"><div class="name">Reserved for #' + num + '</div></div>'
    +   '<div class="meta"><span class="loc">Your seat is open.</span></div>'
    +   '<div class="joined">Become a Founding Member</div>'
    + '</article>';
}

function renderGrid() {
  var grid = document.getElementById("memberGrid");
  var meta = document.getElementById("resultCount");
  var clearBtn = document.getElementById("clearFilters");
  var loadMoreRow = document.getElementById("loadMoreRow");

  var filtered = getFiltered();
  var anyFilter = state.search || state.county || state.tiers.size > 0 || state.electedOnly;
  clearBtn.hidden = !anyFilter;

  if (filtered.length === 0) {
    grid.innerHTML = ''
      + '<div class="no-results" style="grid-column: 1 / -1;">'
      +   '<h4>No members match those filters yet.</h4>'
      +   '<p>Try clearing a filter, or be the first from your county to join.</p>'
      + '</div>';
    meta.textContent = '0 members';
    loadMoreRow.hidden = true;
    return;
  }

  var visibleCounties = {};
  filtered.forEach(function (m) { if (m.county) visibleCounties[m.county] = true; });
  var cText = filtered.length.toLocaleString() + ' member' + (filtered.length === 1 ? '' : 's');
  var cyCount = Object.keys(visibleCounties).length;
  if (cyCount > 0) cText += ' across ' + cyCount + ' count' + (cyCount === 1 ? 'y' : 'ies');
  meta.textContent = cText;

  var slice = filtered.slice(0, state.visibleCount);
  var html = slice.map(memberCardHTML).join("");

  if (!anyFilter && filtered.length < 12 && state.visibleCount === PAGE_SIZE) {
    var lastId = Math.max.apply(null, filtered.map(function (m) { return m.id; }));
    var n = Math.min(8, 12 - filtered.length);
    for (var i = 1; i <= n; i++) html += placeholderCardHTML(lastId + i);
  }

  grid.innerHTML = html;

  if (filtered.length > state.visibleCount) {
    loadMoreRow.hidden = false;
    document.getElementById("loadMoreBtn").textContent =
      'Show more members (' + (filtered.length - state.visibleCount).toLocaleString() + ' remaining)';
  } else {
    loadMoreRow.hidden = true;
  }
}

function debounce(fn, wait) {
  var t;
  return function () {
    var args = arguments;
    clearTimeout(t);
    t = setTimeout(function () { fn.apply(null, args); }, wait);
  };
}

function bindControls() {
  var search = document.getElementById("searchInput");
  var county = document.getElementById("countyFilter");
  var sort = document.getElementById("sortSelect");
  var elected = document.getElementById("electedToggle");
  var clearBtn = document.getElementById("clearFilters");
  var loadMore = document.getElementById("loadMoreBtn");

  search.addEventListener("input", debounce(function (e) {
    state.search = e.target.value;
    state.visibleCount = PAGE_SIZE;
    renderGrid();
  }, 120));

  county.addEventListener("change", function (e) {
    state.county = e.target.value;
    state.visibleCount = PAGE_SIZE;
    renderGrid();
  });

  sort.addEventListener("change", function (e) {
    state.sort = e.target.value;
    renderGrid();
  });

  elected.addEventListener("change", function (e) {
    state.electedOnly = e.target.checked;
    state.visibleCount = PAGE_SIZE;
    renderGrid();
  });

  clearBtn.addEventListener("click", function () {
    state.search = "";
    state.county = "";
    state.tiers = new Set();
    state.electedOnly = false;
    state.visibleCount = PAGE_SIZE;
    search.value = "";
    county.value = "";
    elected.checked = false;
    document.querySelectorAll(".tier-chip").forEach(function (b) { b.setAttribute("aria-pressed", "false"); });
    renderGrid();
  });

  loadMore.addEventListener("click", function () {
    state.visibleCount += PAGE_SIZE;
    renderGrid();
  });
}

// Map a row from the Supabase public view to the page schema
function adaptSupabaseRow(row) {
  var tierName = row.tier || "";
  var tierSlug = tierName.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "");
  if (!tierMap[tierSlug]) tierSlug = "founding-member";
  var name = row.display_name || "Anonymous";
  var parts = name.trim().split(/\s+/);
  var sortName = parts.length > 1
    ? parts[parts.length - 1] + ", " + parts.slice(0, -1).join(" ")
    : name;
  var joined = "";
  if (row.contributed_at) {
    joined = String(row.contributed_at).slice(0, 10);
  }
  return {
    id: row.founding_number || 0,
    displayName: name,
    sortName: sortName,
    city: row.city || null,
    county: row.county || null,
    tier: tierSlug,
    joinedAt: joined,
    electedOffice: row.elected_office || null,
    jurisdiction: row.jurisdiction || null,
    quote: row.public_quote || null,
    publicConsent: true
  };
}

function fetchMembersFromSupabase() {
  var url = SUPABASE_URL
    + "/rest/v1/founding_members_public"
    + "?select=*&order=founding_number.asc";
  return fetch(url, {
    headers: {
      apikey: SUPABASE_ANON_KEY,
      Authorization: "Bearer " + SUPABASE_ANON_KEY,
      Accept: "application/json"
    }
  }).then(function (res) {
    if (!res.ok) throw new Error("Supabase fetch failed: " + res.status);
    return res.json();
  });
}

function renderAll() {
  renderHeroStats();
  renderTierChips();
  renderCountyOptions();
  renderEndorsedStrip();
  renderGrid();
}

function init() {
  // Paint immediately from the embedded snapshot so the page never blanks.
  bindControls();
  renderAll();

  // Then refresh from Supabase if reachable.
  try {
    fetchMembersFromSupabase()
      .then(function (rows) {
        if (Array.isArray(rows) && rows.length > 0) {
          MEMBERS = rows.map(adaptSupabaseRow);
          renderAll();
        }
      })
      .catch(function (err) {
        if (window && window.console) console.warn("Founding members live fetch failed, using snapshot.", err);
      });
  } catch (e) {
    if (window && window.console) console.warn("Founding members fetch threw, using snapshot.", e);
  }
}

init();
